using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var host = builder.Build();
var chatClient = host.Services.GetRequiredService<IChatClient>();

// Tools available to the agent
var notepad = new Notepad();
var tools = new AIFunctionFactory[]{ };
var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// Prompt the user for a research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Configure and run the agent
var agent = new ChatClientAgent(chatClient,
    $"""
    You are a research agent. Your goal is to thoroughly research the given topic using the
    available tools, then produce a concise summary of your findings.

    Instructions:
    1. Use the SearchWeb tool to search for information about the topic. Make multiple searches
       with different queries to get comprehensive coverage.
    2. Use the AddNote tool to save important facts and findings as you discover them.
    3. Use the GetNotes tool to review what you've collected.
    4. After gathering enough information (at least 3 searches), compile your notes into a
       well-structured summary and present it to the user.

    Be thorough but focused. Cite your sources when possible.
    """,
    new ChatClientAgentOptions { Tools = aiTools });

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 15,
};

Console.WriteLine("--- Agent Working ---\n");

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n--- Research Complete ---");

// --- Tool Definitions ---

/// <summary>Simulates web search results. Replace with a real search API (e.g., Bing Search) for production use.</summary>
static class WebSearchTool
{
    [Description("Searches the web for information on a given query and returns relevant results.")]
    public static Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        // In production, replace this with a call to Bing Search API, Google Custom Search, etc.
        var result = $"""
            Search results for: "{query}"

            1. [Wikipedia] Overview article discussing key aspects of {query}, including history,
               current developments, and notable figures in the field.
               Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}

            2. [Research Journal] Recent peer-reviewed study examining the latest findings related
               to {query}, published in 2025. Highlights emerging trends and data.
               Source: https://journals.example.com/article/{query.GetHashCode():X}

            3. [News] Recent news coverage about {query}, discussing current events and
               public discourse surrounding the topic.
               Source: https://news.example.com/{Uri.EscapeDataString(query)}
            """;

        return Task.FromResult(result);
    }
}

/// <summary>A notepad tool that allows the agent to save and retrieve research notes.</summary>
class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record important facts and findings.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

